#include <sstream>

namespace RawrXD {

class CPUInferenceEngine::Impl {
public:
    RawrXDInference inference;
    RawrXDTokenizer tokenizer;
    RawrXDSampler sampler;
    bool modelLoaded = false;
    std::string modelPath;
    std::vector<int> recentTokens;
    size_t maxRecent = 512;
    
    Impl() {
        // Initialize sampler with defaults
        RawrXDSampler::Config cfg;
        cfg.temperature = 0.8f;
        cfg.topK = 40;
        cfg.topP = 0.9f;
        cfg.repetitionPenalty = 1.1f;
        cfg.seed = 0xDEADBEEF;
        sampler.SetConfig(cfg);
    }
};

CPUInferenceEngine::CPUInferenceEngine() : m_impl(std::make_unique<Impl>()) {}

CPUInferenceEngine::~CPUInferenceEngine() = default;

RawrXD::Expected<void, InferenceError> CPUInferenceEngine::loadModel(const std::string& path) {
    try {
        // Convert path to wstring for Windows API
        std::wstring wpath(path.begin(), path.end());
        
        // Initialize real inference engine
        if (!m_impl->inference.Initialize(
            wpath.c_str(),
            "tokenizer.json",
            "merges.txt")) {
            return RawrXD::Unexpected<InferenceError>(InferenceError::LoadFailed);
        }
        
        // Load tokenizer
        if (!m_impl->tokenizer.Load("tokenizer.json", "merges.txt")) {
            return RawrXD::Unexpected<InferenceError>(InferenceError::TokenizerFailed);
        }
        
        m_impl->modelLoaded = true;
        m_impl->modelPath = path;
        return {};
    } catch (const std::exception& e) {
        return RawrXD::Unexpected<InferenceError>(InferenceError::LoadFailed);
    }
}

bool CPUInferenceEngine::isModelLoaded() const {
    return m_impl->modelLoaded;
}

RawrXD::Expected<CPUInferenceEngine::GenerationResult, InferenceError> CPUInferenceEngine::generate(
        const std::string& prompt,
        float temp,
        float top_p,
        int max_tokens) {
    
    if (!m_impl->modelLoaded) {
        return RawrXD::Unexpected<InferenceError>(InferenceError::ModelNotLoaded);
    }
    
    try {
        // Update sampler config
        RawrXDSampler::Config cfg;
        cfg.temperature = temp;
        cfg.topP = top_p;
        cfg.maxTokens = max_tokens;
        m_impl->sampler.SetConfig(cfg);
        
        // Tokenize input
        auto tokens = m_impl->tokenizer.Encode(prompt, true, false);
        if (tokens.empty()) {
            return RawrXD::Unexpected<InferenceError>(InferenceError::TokenizationFailed);
        }
        
        // Initial forward pass
        auto logits = m_impl->inference.Forward(tokens, 0);
        if (logits.empty()) {
            return RawrXD::Unexpected<InferenceError>(InferenceError::InferenceFailed);
        }
        
        // Generate tokens
        std::vector<int> generated;
        for (int i = 0; i < max_tokens; i++) {
            int token = m_impl->sampler.Sample(logits.data(), logits.size(), tokens);
            generated.push_back(token);
            tokens.push_back(token);
            
            // Check for EOS
            if (token == 2) break; // EOS token
            
            // Incremental forward pass
            logits = m_impl->inference.Forward({token}, tokens.size() - 1);
        }
        
        // Detokenize response
        std::string response = m_impl->tokenizer.Decode(generated);
        
        return GenerationResult{
            response,
            1.0f,  // confidence score (placeholder)
            static_cast<int>(generated.size())
        };
        
    } catch (const std::exception& e) {
        return RawrXD::Unexpected<InferenceError>(InferenceError::InferenceFailed);
    }
}

std::vector<int> CPUInferenceEngine::Tokenize(const std::string& text) {
    if (!m_impl->modelLoaded) return {};
    return m_impl->tokenizer.Encode(text, true, false);
}

std::string CPUInferenceEngine::Detokenize(const std::vector<int>& tokens) {
    if (!m_impl->modelLoaded) return "";
    return m_impl->tokenizer.Decode(tokens);
}

void CPUInferenceEngine::GenerateStreaming(const std::vector<int>& inputTokens, int maxTokens, 
                                          StreamCallback onToken, DoneCallback onDone) {
    if (!m_impl->modelLoaded || !onToken || !onDone) {
        onDone();
        return;
    }
    
    try {
        auto tokens = inputTokens;
        auto logits = m_impl->inference.Forward(tokens, 0);
        
        for (int i = 0; i < maxTokens; i++) {
            int token = m_impl->sampler.Sample(logits.data(), logits.size(), tokens);
            
            // Call streaming callback
            std::string piece = m_impl->tokenizer.Decode({token});
            onToken(piece);
            
            tokens.push_back(token);
            
            if (token == 2) break; // EOS
            
            logits = m_impl->inference.Forward({token}, tokens.size() - 1);
        }
        
        onDone();
    } catch (...) {
        onDone();
    }
}

nlohmann::json CPUInferenceEngine::getStatus() const {
    nlohmann::json status;
    status["model_loaded"] = m_impl->modelLoaded;
    status["model_path"] = m_impl->modelPath;
    status["engine"] = "RawrXD_CPU";
    status["max_context"] = 4096;
    status["vocab_size"] = 32000;
    return status;
}

} // namespace RawrXD
