AgenticEngine::AgenticEngine() : inference_engine_(nullptr), config_(), history_() {}

AgenticEngine::~AgenticEngine() = default;

void AgenticEngine::setInferenceEngine(RawrXD::CPUInferenceEngine* engine) {
    inference_engine_ = engine;
}

void AgenticEngine::updateConfig(const GenerationConfig& config) {
    config_ = config;
}

void AgenticEngine::clearHistory() {
    history_.clear();
}

void AgenticEngine::appendSystemPrompt(const std::string& prompt) {
    history_.push_back({"system", prompt});
}

void AgenticEngine::loadContext(const std::string& context) {
    // Load from file or database
    std::ifstream file(context);
    if (file.is_open()) {
        std::stringstream buffer;
        buffer << file.rdbuf();
        appendSystemPrompt(buffer.str());
    }
}

void AgenticEngine::saveContext(const std::string& path) {
    // Save to file
    std::ofstream file(path);
    if (file.is_open()) {
        for (const auto& msg : history_) {
            file << "[" << msg.role << "] " << msg.content << "\n";
        }
    }
}

std::string AgenticEngine::planTask(const std::string& task) {
    if (!inference_engine_) return "";
    
    std::string prompt = "Create a step-by-step plan to: " + task + "\n\nPlan:";
    
    auto result = inference_engine_->generate(prompt, 0.7f, 0.9f, 512);
    if (result.has_value()) {
        return result.value().text;
    }
    
    return "";
}

std::string AgenticEngine::executePlan(const std::string& plan) {
    if (!inference_engine_) return "";
    
    std::string prompt = "Execute this plan and provide results:\n\n" + plan + "\n\nResults:";
    
    auto result = inference_engine_->generate(prompt, 0.8f, 0.9f, 1024);
    if (result.has_value()) {
        return result.value().text;
    }
    
    return "";
}

std::string AgenticEngine::chat(const std::string& message) {
    if (!inference_engine_) return "";
    
    // Add user message to history
    history_.push_back({"user", message});
    
    // Build prompt from history
    std::string prompt;
    for (const auto& msg : history_) {
        prompt += msg.role + ": " + msg.content + "\n";
    }
    prompt += "assistant: ";
    
    // Generate response
    auto result = inference_engine_->generate(prompt, config_.temperature, config_.top_p, config_.max_tokens);
    
    std::string response;
    if (result.has_value()) {
        response = result.value().text;
        history_.push_back({"assistant", response});
    }
    
    return response;
}

std::string AgenticEngine::analyzeCode(const std::string& code) {
    if (!inference_engine_) return "";
    
    std::string prompt = "Analyze this code for bugs, performance issues, and suggest improvements:\n\n```\n" + code + "\n```\n\nAnalysis:";
    
    auto result = inference_engine_->generate(prompt, 0.7f, 0.9f, 1024);
    if (result.has_value()) {
        return result.value().text;
    }
    
    return "";
}

std::string AgenticEngine::generateCode(const std::string& description) {
    if (!inference_engine_) return "";
    
    std::string prompt = "Generate complete, working code for: " + description + "\n\nCode:";
    
    auto result = inference_engine_->generate(prompt, 0.8f, 0.9f, 2048);
    if (result.has_value()) {
        return result.value().text;
    }
    
    return "";
}

std::string AgenticEngine::bugReport(const std::string& code, const std::string& error) {
    if (!inference_engine_) return "";
    
    std::string prompt = "This code produces an error:\n\n```\n" + code + "\n```\n\nError: " + error + "\n\nBug Report:";
    
    auto result = inference_engine_->generate(prompt, 0.7f, 0.9f, 1024);
