void APIServer::ProcessRequest(const APIRequest& request) {
    APIResponse response;
    response.id = request.id;
    
    try {
        if (request.type == "generate") {
            // Generate text
            auto result = app_state_.inference_engine->generate(
                request.prompt,
                request.temperature,
                request.top_p,
                request.max_tokens
            );
            
            if (result.has_value()) {
                response.text = result.value().text;
                response.success = true;
            } else {
                response.error = "Generation failed";
                response.success = false;
            }
        } else if (request.type == "tokenize") {
            // Tokenize text
            auto tokens = app_state_.inference_engine->Tokenize(request.prompt);
            response.tokens = tokens;
            response.success = true;
        } else if (request.type == "detokenize") {
            // Detokenize tokens
            std::string text = app_state_.inference_engine->Detokenize(request.tokens);
            response.text = text;
            response.success = true;
        } else if (request.type == "status") {
            // Get status
            response.status = app_state_.inference_engine->getStatus();
            response.success = true;
        } else {
            response.error = "Unknown request type";
            response.success = false;
        }
    } catch (const std::exception& e) {
        response.error = e.what();
        response.success = false;
    }
    
    // Send response
    SendResponse(response);
}

