OverclockGovernor::OverclockGovernor() : running_(false), governor_thread_(nullptr), app_state_(nullptr) {}

OverclockGovernor::~OverclockGovernor() {
    Stop();
}

bool OverclockGovernor::Start(AppState& state) {
    if (running_) return false;
    
    app_state_ = &state;
    running_ = true;
    
    governor_thread_ = new std::thread([this]() {
        RunGovernor();
    });
    
    std::cout << "[Governor] Started" << std::endl;
    return true;
}

void OverclockGovernor::Stop() {
    if (!running_) return;
    
    running_ = false;
    
    if (governor_thread_ && governor_thread_->joinable()) {
        governor_thread_->join();
        delete governor_thread_;
        governor_thread_ = nullptr;
    }
    
    std::cout << "[Governor] Stopped" << std::endl;
}

void OverclockGovernor::RunGovernor() {
    while (running_) {
        telemetry::Snapshot snap;
        telemetry::Poll(snap);
        
        if (!app_state_) {
            std::this_thread::sleep_for(std::chrono::milliseconds(500));
            continue;
        }
        
        // Temperature-based throttling
        if (snap.cpuTempValid && snap.cpuTempC > app_state_->target_cpu_temp_c) {
            // Too hot, reduce clocks
            overclock_vendor::ApplyCpuOffsetMhz(-25);
            std::cout << "[Governor] CPU temp " << snap.cpuTempC << "C > target " 
                     << app_state_->target_cpu_temp_c << "C, reducing clocks" << std::endl;
        } else if (snap.cpuTempValid && snap.cpuTempC < app_state_->target_cpu_temp_c - 5) {
            // Cool enough, increase clocks
            overclock_vendor::ApplyCpuOffsetMhz(25);
            std::cout << "[Governor] CPU temp " << snap.cpuTempC << "C < target " 
                     << app_state_->target_cpu_temp_c - 5 << "C, increasing clocks" << std::endl;
        }
        
        // GPU throttling
        if (snap.gpuTempValid && snap.gpuTempC > app_state_->target_gpu_temp_c) {
            overclock_vendor::ApplyGpuClockOffsetMhz(-50);
            std::cout << "[Governor] GPU temp " << snap.gpuTempC << "C > target " 
                     << app_state_->target_gpu_temp_c << "C, reducing clocks" << std::endl;
        }
        
        std::this_thread::sleep_for(std::chrono::milliseconds(500));
    }
}
