                        std::cout << "Saved.\n";
                    }
                }
            } else {
                std::cout << "File not found.\n";
            }
            continue;
        }
        
        if (input == "/bugreport") {
            std::cout << "\n[Agent] Analyzing codebase for bugs...\n";
            // Get current directory
            std::string path = std::filesystem::current_path().string();
            std::string prompt = "Analyze this codebase for bugs: " + path;
            std::string analysis = agent.analyzeCode(prompt);
            std::cout << "\n[Bug Report]\n" << analysis << "\n";
            continue;
