        if (input == "/suggest") {
            std::cout << "\n[Agent] Generating code suggestions...\n";
            // Get current file
            std::string path = std::filesystem::current_path().string();
            std::string prompt = "Review this codebase and provide suggestions: " + path;
            std::string suggestions = agent.codeSuggestions(prompt);
            std::cout << "\n[Suggestions]\n" << suggestions << "\n";
            continue;
        }
        
        if (input == "/clear") {
            agent.clearHistory();
            std::cout << "[Agent] History cleared.\n";
            continue;
        }
        
        if (input.empty()) continue;

        // Standard Streaming Chat
        std::cout << "\nRawrXD: ";
        auto tokens = state.inference_engine->Tokenize(input);
