    while (running) {
        std::cout << "\n=== RawrXD Main Menu ===\n";
        std::cout << "Model: " << state.model_path << "\n";
        std::cout << "[c] Chat Mode\n";
        std::cout << "[a] Agentic Mode\n";
        std::cout << "[s] Settings\n";
        std::cout << "[t] Telemetry\n";
        std::cout << "[g] Toggle Governor\n";
        std::cout << "[q] Quit\n";
        std::cout << "Choice: ";
        
        char choice = _getch();
        std::cout << choice << "\n";
        
        switch (choice) {
            case 'c':
                RunInteractiveChat(state, agent);
                break;
            case 'a':
                {
                    std::cout << "\n[Agentic Mode]\n";
                    std::cout << "Enter task description: ";
                    std::string task;
                    std::getline(std::cin, task);
                    std::string plan = agent.planTask(task);
                    std::cout << "\n[Plan]\n" << plan << "\n";
                    std::cout << "\nExecute plan? (y/n): ";
                    char exec = _getch();
                    if (exec == 'y' || exec == 'Y') {
                        std::string result = agent.executePlan(plan);
                        std::cout << "\n[Results]\n" << result << "\n";
                    }
                }
                break;
            case 's':
                {
                    std::cout << "\n[Settings]\n";
                    std::cout << "Temperature: " << state.temperature << "\n";
                    std::cout << "Top-P: " << state.top_p << "\n";
                    std::cout << "Max Tokens: " << state.max_tokens << "\n";
                    std::cout << "Governor: " << (state.enable_overclock_governor ? "ON" : "OFF") << "\n";
                }
                break;
            case 't':
                {
                    telemetry::Snapshot snap;
                    telemetry::Poll(snap);
                    std::cout << "\n[Telemetry]\n";
                    if (snap.cpuTempValid) std::cout << "CPU Temp: " << snap.cpuTempC << "C\n";
                    if (snap.gpuTempValid) std::cout << "GPU Temp: " << snap.gpuTempC << "C\n";
                    std::cout << "CPU Clock: " << snap.cpuClockMhz << " MHz\n";
                    std::cout << "GPU Clock: " << snap.gpuClockMhz << " MHz\n";
                }
                break;
            case 'g':
                if (governor_running) {
                    governor.Stop();
                    governor_running = false;
                    std::cout << "[Governor] Stopped\n";
                } else {
                    governor.Start(state);
                    governor_running = true;
                    std::cout << "[Governor] Started\n";
                }
                break;
            case 'q':
                running = false;
                break;
        }
    }

    if (governor_running) governor.Stop();
    api.Stop();
    telemetry::Shutdown();
    
    std::cout << "\n[Shutdown] RawrXD terminated gracefully.\n";
    return 0;
}
